// src/components/Navbar.jsx  — mobile-responsive with hamburger menu
import React, { useState, useEffect, useRef } from 'react';
import GlobeLogo from './GlobeLogo';
import LanguageSelector from './LanguageSelector';

const NAV_ITEMS = [
  { page: 'home',     label: 'Home'        },
  { page: 'location', label: 'Location'    },
  { page: 'dest',     label: 'Destination' },
  { page: 'trains',   label: 'Trains'      },
  { page: 'lastmile', label: 'Last Mile'   },
];

export default function Navbar({ currentPage, onNavigate, speak }) {
  const [menuOpen, setMenuOpen] = useState(false);
  const menuRef  = useRef(null);

  useEffect(() => {
    function handleOutside(e) {
      if (menuOpen && menuRef.current && !menuRef.current.contains(e.target)) {
        setMenuOpen(false);
      }
    }
    document.addEventListener('mousedown', handleOutside);
    document.addEventListener('touchstart', handleOutside);
    return () => {
      document.removeEventListener('mousedown', handleOutside);
      document.removeEventListener('touchstart', handleOutside);
    };
  }, [menuOpen]);

  function navigate(page) {
    setMenuOpen(false);
    onNavigate(page);
  }

  const navBtnStyle = (active) => ({
    background: active ? '#6BAF45' : 'transparent',
    color: active ? '#fff' : '#6a6a64',
    border: 'none', cursor: 'pointer',
    padding: '8px 14px', borderRadius: 8,
    fontSize: '.82rem', fontWeight: active ? 600 : 500,
    fontFamily: 'Inter, sans-serif', transition: 'all .2s',
    whiteSpace: 'nowrap',
  });

  return (
    <div ref={menuRef}>
      <nav style={{
        position: 'fixed', top: 0, left: 0, right: 0, zIndex: 5000,
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        padding: '10px 20px',
        background: 'rgba(255,255,255,0.97)',
        backdropFilter: 'blur(22px)',
        borderBottom: '1px solid rgba(0,0,0,.07)',
        boxShadow: '0 1px 12px rgba(0,0,0,.06)',
        animation: 'slideDown .8s ease forwards',
        minHeight: 60,
      }}>

        {/* Brand */}
        <div
          onClick={() => navigate('home')}
          style={{ display: 'flex', alignItems: 'center', gap: 10, cursor: 'pointer', userSelect: 'none', flexShrink: 0 }}
        >
          <div style={{
            background: '#1e1e1c', borderRadius: '50%', padding: 3,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
          }}>
            <GlobeLogo size={32} />
          </div>
          <div style={{
            fontFamily: 'Playfair Display, serif', fontWeight: 900,
            fontSize: '1.25rem', color: '#1a1a19', letterSpacing: 5, lineHeight: 1,
          }}>VISTA</div>
        </div>

        {/* Desktop nav links */}
        <div className="vista-nav-links" style={{ display: 'flex', alignItems: 'center', gap: 2 }}>
          {NAV_ITEMS.map(item => (
            <button
              key={item.page}
              onClick={() => navigate(item.page)}
              style={navBtnStyle(currentPage === item.page)}
              onMouseEnter={e => { if (currentPage !== item.page) { e.target.style.color = '#1a1a19'; e.target.style.background = 'rgba(0,0,0,.05)'; }}}
              onMouseLeave={e => { if (currentPage !== item.page) { e.target.style.color = '#6a6a64'; e.target.style.background = 'transparent'; }}}
            >{item.label}</button>
          ))}

          <button
            onClick={() => window.dispatchEvent(new CustomEvent('vista-open-help'))}
            style={navBtnStyle(false)}
            onMouseEnter={e => { e.currentTarget.style.color = '#1a1a19'; e.currentTarget.style.background = 'rgba(0,0,0,.05)'; }}
            onMouseLeave={e => { e.currentTarget.style.color = '#6a6a64'; e.currentTarget.style.background = 'transparent'; }}
          >Help</button>

          <div style={{ marginLeft: 4 }}>
            <LanguageSelector speak={speak} compact={true} />
          </div>

          <button
            onClick={() => navigate('location')}
            style={{
              marginLeft: 8, padding: '9px 20px', borderRadius: 50,
              background: '#1e1e1c', color: '#ffffff', border: 'none', cursor: 'pointer',
              fontFamily: 'Inter, sans-serif', fontSize: '.83rem', fontWeight: 600,
              letterSpacing: '.3px', boxShadow: '0 2px 10px rgba(0,0,0,.15)', transition: 'all .25s',
              whiteSpace: 'nowrap',
            }}
            onMouseEnter={e => { e.currentTarget.style.background = '#333'; }}
            onMouseLeave={e => { e.currentTarget.style.background = '#1e1e1c'; }}
          >Start Journey</button>
        </div>

        {/* Mobile: Language + Hamburger */}
        <div className="vista-hamburger" style={{ display: 'none', alignItems: 'center', gap: 8 }}>
          <LanguageSelector speak={speak} compact={true} />
          <button
            onClick={() => setMenuOpen(o => !o)}
            aria-label={menuOpen ? 'Close menu' : 'Open menu'}
            style={{
              background: menuOpen ? 'rgba(107,175,69,.1)' : 'transparent',
              border: '1.5px solid rgba(0,0,0,.1)',
              borderRadius: 8, cursor: 'pointer',
              padding: '6px 8px',
              display: 'flex', flexDirection: 'column', gap: 4,
              alignItems: 'center', justifyContent: 'center',
              width: 40, height: 40, transition: 'all .2s',
            }}
          >
            <span style={{
              display: 'block', width: 20, height: 2, background: '#1e1e1c', borderRadius: 2,
              transition: 'all .25s',
              transform: menuOpen ? 'rotate(45deg) translate(4px, 4px)' : 'none',
            }} />
            <span style={{
              display: 'block', width: 20, height: 2, background: '#1e1e1c', borderRadius: 2,
              transition: 'all .25s', opacity: menuOpen ? 0 : 1,
            }} />
            <span style={{
              display: 'block', width: 20, height: 2, background: '#1e1e1c', borderRadius: 2,
              transition: 'all .25s',
              transform: menuOpen ? 'rotate(-45deg) translate(4px, -4px)' : 'none',
            }} />
          </button>
        </div>
      </nav>

      {/* Mobile dropdown menu */}
      <div className={`vista-mobile-menu${menuOpen ? ' open' : ''}`}>
        {NAV_ITEMS.map(item => (
          <button
            key={item.page}
            onClick={() => navigate(item.page)}
            style={{
              background: currentPage === item.page ? 'rgba(107,175,69,.08)' : 'transparent',
              color: currentPage === item.page ? '#4a8a2a' : '#3a3a38',
              border: 'none', cursor: 'pointer',
              padding: '14px 24px', fontSize: '.95rem',
              fontWeight: currentPage === item.page ? 700 : 400,
              fontFamily: 'Inter, sans-serif', textAlign: 'left', width: '100%',
              borderLeft: currentPage === item.page ? '3px solid #6BAF45' : '3px solid transparent',
              transition: 'all .15s',
            }}
          >{item.label}</button>
        ))}

        <button
          onClick={() => { setMenuOpen(false); window.dispatchEvent(new CustomEvent('vista-open-help')); }}
          style={{
            background: 'transparent', color: '#3a3a38', border: 'none',
            cursor: 'pointer', padding: '14px 24px', fontSize: '.95rem',
            fontFamily: 'Inter, sans-serif', textAlign: 'left', width: '100%',
            borderLeft: '3px solid transparent',
          }}
        >Help</button>

        <button
          onClick={() => navigate('location')}
          style={{
            margin: '10px 20px 0', width: 'calc(100% - 40px)',
            padding: '13px 20px', borderRadius: 50,
            background: '#1e1e1c', color: '#fff',
            border: 'none', cursor: 'pointer',
            fontFamily: 'Inter, sans-serif', fontSize: '.9rem', fontWeight: 600,
          }}
        >Start Journey →</button>
      </div>
    </div>
  );
}
